// Meta sends GET ?hub.mode=subscribe&hub.verify_token=...&hub.challenge=...
// We reply 200 + the challenge string ONLY when verify_token matches our env. Else 403.
const q = $('Webhook: Meta Verification (GET)').first().json.query || {};
const expected = $env.META_VERIFY_TOKEN || '';
const mode = q['hub.mode'];
const token = q['hub.verify_token'];
const challenge = q['hub.challenge'];
if (mode === 'subscribe' && token === expected && expected.length > 0) {
  return [{ json: { ok: true, challenge: String(challenge || '') } }];
}
return [{ json: { ok: false, reason: 'verify_token mismatch or env not set', received_token_present: !!token } }];

// HMAC SHA-256 signature verification per Meta's webhook contract.
// Header: X-Hub-Signature-256: sha256=<hex>
// Expected = HMAC_SHA256(app_secret, raw_body).hex()
// We use timingSafeEqual to avoid leaking via timing.
const crypto = require('crypto');
const incoming = $('Webhook: Meta Leadgen (POST)').first().json;
const headers = incoming.headers || {};
const rawBody = incoming.body || incoming.rawBody || '';
const secret = $env.META_APP_SECRET || '';

const providedSig = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || '';

let valid = false;
let failureReason = null;

if (!secret) {
  failureReason = 'META_APP_SECRET env not set';
} else if (!providedSig.startsWith('sha256=')) {
  failureReason = 'X-Hub-Signature-256 header missing or malformed';
} else {
  try {
    const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody)).digest('hex');
    const a = Buffer.from(providedSig);
    const b = Buffer.from(expected);
    valid = a.length === b.length && crypto.timingSafeEqual(a, b);
    if (!valid) failureReason = 'signature_mismatch';
  } catch (e) {
    failureReason = 'hmac_compute_failure: ' + e.message;
  }
}

// Parse the body for downstream nodes. If rawBody is already an object (older n8n), pass through.
let parsedBody;
try { parsedBody = typeof rawBody === 'string' ? JSON.parse(rawBody) : rawBody; } catch (e) { parsedBody = {}; }

return [{ json: { valid, failureReason, parsedBody } }];

// Flatten the entry/changes structure into one item per leadgen_id.
// Meta's leadgen webhook body looks like:
//   { object: 'page', entry: [{ id: page_id, time, changes: [{ field: 'leadgen', value: { leadgen_id, page_id, form_id, ad_id, adgroup_id, created_time } }] }] }
const body = $('Code: Verify HMAC Signature').first().json.parsedBody || {};
const entries = Array.isArray(body.entry) ? body.entry : [];
const out = [];
for (const e of entries) {
  const changes = Array.isArray(e.changes) ? e.changes : [];
  for (const c of changes) {
    if (c.field !== 'leadgen') continue;
    const v = c.value || {};
    if (!v.leadgen_id) continue;
    out.push({ json: {
      leadgen_id: String(v.leadgen_id),
      form_id:    String(v.form_id || ''),
      page_id:    String(v.page_id || e.id || ''),
      ad_id:      String(v.ad_id || ''),
      adgroup_id: String(v.adgroup_id || ''),
      created_time: v.created_time || e.time || null
    }});
  }
}
if (out.length === 0) return [{ json: { _empty: true, reason: 'no_leadgen_changes_in_payload' } }];
return out;

// v2 graceful Graph API failure handling: when leads_retrieval permission is not
// granted (Meta App Review pending), the Graph API returns 401/403 and field_data
// is empty. We still proceed with sensible test-data defaults so the rest of the
// agent chain demonstrates end-to-end. In production with App Review approved,
// the graph.field_data array is populated and the fallbacks are unused.
const graph = $('HTTP: Graph API Fetch Field Data').first().json || {};
const lookupArr = $('HTTP: Supabase Form Lookup').first().json;
const lookup = Array.isArray(lookupArr) ? (lookupArr[0] || {}) : (lookupArr || {});
const leadgen = $('Code: Extract Leadgen IDs').first().json;

const graphApiFailed = !!(graph.error) || !Array.isArray(graph.field_data);
const graphErrorCode = graph?.error?.code || null;

// field_data is [{name, values: [...]}]. Collapse into a {field_name: first_value} map.
const fields = {};
const rawFD = Array.isArray(graph.field_data) ? graph.field_data : [];
for (const f of rawFD) {
  if (f && f.name) fields[String(f.name).toLowerCase()] = Array.isArray(f.values) ? f.values[0] : null;
}

// Standard Meta autofill names. Fall back to a recognizable test profile when
// the Graph API call failed (leads_retrieval not yet granted via App Review).
// Test profile uses the form_id to create deterministic but unique test leads —
// so every test submission from Meta Testing Tool produces a different row.
function shortId(s) { return String(s || 'na').slice(-6); }
const testTag = shortId(leadgen.leadgen_id);

const name  = fields['full_name'] || fields['name'] || fields['first_name'] || (graphApiFailed ? `Meta Test Lead ${testTag}` : null);
const phone = fields['phone_number'] || fields['phone'] || (graphApiFailed ? '+91999' + testTag.padStart(7, '0') : null);
const email = fields['email'] || (graphApiFailed ? `test+${testTag}@meta-leadgen.test` : null);

// Custom questions — best-effort mapping. The field_map column on meta_form_to_property
// lets a user override this per form.
const fieldMap = (lookup && lookup.field_map && typeof lookup.field_map === 'object') ? lookup.field_map : {};
function read(key, fallback) { return (fieldMap[key] && fields[String(fieldMap[key]).toLowerCase()]) || fields[key] || fallback || null; }

const bhk      = read('preferred_config', null) || fields['bhk_preference'] || fields['what_bhk_are_you_looking_for'] || null;
const budgetStr = read('budget_lakhs', null) || fields['your_budget'] || fields['budget_range'] || null;
const city     = read('preferred_city', null) || lookup.city || null;

// Convert budget strings like '2-4 Cr' or '<2 Cr' or '4 Cr+' to a single lakhs number (midpoint).
function parseBudgetToLakhs(s) {
  if (!s) return null;
  const t = String(s).toLowerCase().replace(/,/g, ' ').replace(/\s+/g, ' ').trim();
  const crToL = (n) => Math.round(parseFloat(n) * 100);
  const lakhsToL = (n) => Math.round(parseFloat(n));
  // patterns: '2-4 cr' | '2 to 4 cr' | '<2 cr' | '4 cr+' | '80 lakhs' | '1.5 cr'
  let m;
  if ((m = t.match(/(\d+\.?\d*)\s*[-to]+\s*(\d+\.?\d*)\s*cr/))) return Math.round((crToL(m[1]) + crToL(m[2])) / 2);
  if ((m = t.match(/(\d+\.?\d*)\s*[-to]+\s*(\d+\.?\d*)\s*lakh/))) return Math.round((lakhsToL(m[1]) + lakhsToL(m[2])) / 2);
  if ((m = t.match(/(?:under|<|less than)\s*(\d+\.?\d*)\s*cr/))) return crToL(m[1]) * 0.85;
  if ((m = t.match(/(\d+\.?\d*)\s*cr\+/))) return crToL(m[1]) * 1.15;
  if ((m = t.match(/(\d+\.?\d*)\s*cr/))) return crToL(m[1]);
  if ((m = t.match(/(\d+\.?\d*)\s*lakh/))) return lakhsToL(m[1]);
  return null;
}
const budgetLakhs = parseBudgetToLakhs(budgetStr);

const inquiryParts = [];
if (bhk) inquiryParts.push('BHK: ' + bhk);
if (budgetStr) inquiryParts.push('Budget: ' + budgetStr);
if (lookup.project_name) inquiryParts.push('Project: ' + lookup.project_name);
inquiryParts.push(graphApiFailed
  ? `(Meta Lead Form — test submission; field_data unavailable, leads_retrieval pending App Review)`
  : '(via Meta Lead Form)');

// For test submissions, inject the property's price band as the buyer's apparent budget
// so the Lead Agent's RAG retrieval has signal to work with. Real submissions use the
// buyer-provided budget from the form.
const inferredBudget = budgetLakhs || (graphApiFailed && lookup.price_min_lakhs && lookup.price_max_lakhs
  ? Math.round((Number(lookup.price_min_lakhs) + Number(lookup.price_max_lakhs)) / 2)
  : null);

const payload = {
  name: name || 'Unknown (Meta)',
  phone: phone,
  email: email,
  source: 'Meta Ad',
  inquiry_text: inquiryParts.join('. '),
  interested_project: lookup.project_name || null,
  preferred_config: bhk || (graphApiFailed && lookup.config ? lookup.config.split(',')[0].trim() : null),
  budget_lakhs: inferredBudget,
  preferred_city: city,
  meta_attribution: {
    leadgen_id: leadgen.leadgen_id,
    form_id: leadgen.form_id,
    page_id: leadgen.page_id,
    ad_id: leadgen.ad_id,
    adgroup_id: leadgen.adgroup_id,
    property_id_mapped: lookup.property_id || null,
    graph_api_failed: graphApiFailed,
    graph_api_error_code: graphErrorCode
  }
};

return [{ json: payload }];
